#include <bits/stdc++.h>
using namespace std;

struct card{
    string id,t;
}c[100005];
int n,k,m,p;

void wash(){
    int l=1,r=k/2+1;
    card b[100005];
    for(int i=1;i<=k/2*2;i++)
        if(i%2)
            b[i]=c[r++];
        else
            b[i]=c[l++];
    if(k%2)
        b[k]=c[k];
    for(int i=1;i<=k;i++)
        c[i]=b[i];
}

int main(){
    cin>>n>>k>>m>>p;
    for(int i=1;i<=k;i++)
        cin>>c[i].id>>c[i].t;
    if(n*4>k){
        cout<<"Error:cards not enough";
        return 0;
    }
    while(m--)
        wash();
    for(int i=1;i<=n*4;i++)
        if((i-1)%n+1==p)
            cout<<c[i].id<<' '<<c[i].t<<endl;
    return 0;
}
